  ('disabled-64311456-moex-00075', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '根據兒童及少年福利與權益保障法規定，販賣、交付或供應毒品、非法供 應管制藥品或其他有害身心健康之物質予兒童及少年者，要處以新臺幣多 少數額的罰鍰？', '["二萬元以上三十萬元以下", "四萬元以上三十萬元以下", "六萬元以上三十萬元以下", "十萬元以上三十萬元以下"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00076', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '根據身心障礙者權益保障法對於障礙鑑定及需求評估有異議的規定，下列 敘述何者錯誤？', '["身心障礙者應於收到通知書之次日起三十日內，以書面向直轄市、縣 （市）主管機關提出申請重新鑑定及需求評估", "身心障礙者對障礙鑑定及需求評估有異議而提出申請重新鑑定及需求 評估，以一次為限", "身心障礙者對障礙鑑定及需求評估有異議而提出申請重新鑑定及需求 評估，應負擔相關作業費用的百分之五十", "身心障礙者對障礙鑑定及需求評估有異議而提出申請重新鑑定及需求 評估，其異議成立，應退還其已負擔之相關作業費用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00077', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '根據特殊境遇家庭扶助條例的規定，關於家庭暴力受害的特殊境遇家庭得 申請法律訴訟補助的條件與相關規定，下列敘述何者錯誤？', '["補助最高金額以新臺幣六萬元為限", "應向戶籍所在地之主管機關申請補助", "必須無力負擔訴訟費用者，方得申請", "應於事實發生後三個月內檢具相關證明提出申請"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00078', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '法院於受理緊急保護令之聲請後，依聲請人到庭或電話陳述家庭暴力之事 實，足認被害人有受家庭暴力之急迫危險者，依據家庭暴力防治法，應於 幾個小時內核發緊急保護令？', '["二小時", "八小時", "六小時", "四小時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00079', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '根據性別平等工作法的規定，申訴案件經雇主或地方主管機關調查後，認 定為性騷擾，且情節重大者，雇主得於知悉該調查結果之日起幾日內，可 以不經預告而終止勞動契約？', '["十四日", "七日", "三十日", "六十日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00080', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '根據社會救助法規定，低收入戶成員中領有身心障礙手冊或身心障礙證明 者，主管機關得依其原領取現金給付之金額增加補助，但最高不得超過多 少百分比？', '["百分之四十", "百分之六十", "百分之三十", "百分之五十"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00081', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '根據社會救助法之規定，有一些特定人員因執行業務知悉有社會救助需要 之個人或家庭時，應通報直轄市、縣（市）主管機關。下列那一類人員不 在此範圍內？', '["教育人員", "警察人員", "村（里）長", "醫事人員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00082', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '根據國民年金法的規定，被保險人死亡，喪葬給付應按其月投保金額一次 發給幾個月？', '["五個月", "四個月", "三個月", "二個月"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00083', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '依志願服務法對於促進志願服務措施之規定，下列敘述何者錯誤？', '["志願服務運用單位應為志工辦理意外事故保險", "志工進入收費之公立風景區、未編定座次之康樂場所及文教設施，憑志 願服務榮譽卡得予以半價優待", "志工服務年資滿三年，服務時數達三百小時以上者，得檢具證明文件向 地方主管機關申請核發志願服務榮譽卡", "從事志願服務工作績效優良並經認證之志工，得優先服相關兵役替代役"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00084', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '依據性侵害犯罪防治法之規定，法院、檢察署、司法警察機關及醫療機構 ，應由經專業訓練之專責人員處理性侵害案件。而且，這些專責人員每年 應至少接受幾個小時的性侵害防治專業訓練課程？', '["十二小時", "六小時", "十小時", "二十小時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL)
